#!/usr/bin/env python3
"""
Learning With Samara AI - US Test Prep Patcher
Place this script in the SAME folder as your index.html and run:
    python3 patch_us_testprep.py
Creates: index_updated.html  (rename to index.html to deploy)
"""
import sys, os

SCRIPT_DIR = os.path.dirname(os.path.abspath(__file__))
INPUT_FILE  = os.path.join(SCRIPT_DIR, 'index.html')
OUTPUT_FILE = os.path.join(SCRIPT_DIR, 'index_updated.html')

if not os.path.exists(INPUT_FILE):
    print("ERROR: index.html not found. Put this script in the same folder.")
    sys.exit(1)

print('Reading index.html...')
with open(INPUT_FILE, 'r', encoding='utf-8', errors='replace') as f:
    html = f.read()
original_size = len(html)
print(f'File size: {original_size:,} characters')

def ia(base, find, insert, label):
    idx = base.find(find)
    if idx == -1: print(f"  SKIP [{label}]"); return base
    pos = idx + len(find)
    print(f"  OK [{label}]")
    return base[:pos] + "\n" + insert + base[pos:]

def ib(base, find, insert, label):
    idx = base.find(find)
    if idx == -1: print(f"  SKIP [{label}]"); return base
    print(f"  OK [{label}]")
    return base[:idx] + insert + "\n" + base[idx:]

def ro(base, find, repl, label):
    idx = base.find(find)
    if idx == -1: print(f"  SKIP [{label}]"); return base
    print(f"  OK [{label}]")
    return base[:idx] + repl + base[idx + len(find):]

print('Applying patches...')

